ln_Weight = log(Weight_Data); % ln(Weight)
ln_Height = log(Height_Data); % ln(Height)
DD = polyfit(Height_Data,ln_Weight,1); % ln(Weight) = ln(p) + Height · q
p = exp(DD(2));
q = DD(1);
