log10_Height = log10(Height_Data); % log10(Height)
log10_Weight = log10(Weight_Data); % log10(Weight)
BB = polyfit(log10_Height,log10_Weight,1); % linear fitting: ln(Weight) = ln(m) + k*ln(Height)
m = 10^BB(2);
k = BB(1);
