k30 = EE(2);
k3 = EE(1);
% 05 - Quadratic model: Weight = k20 + k2 * Height^2
Height_Quadratic = Height_Data.^2;
FF = polyfit(Height_Quadratic,Weight_Data,1); % Weight = k20 + k2 * Height^2
k20 = FF(2);
k2 = FF(1);
% 06 - Linear model: Weight = k10 + k1 * Height
