k40 = HH(3);
k41 = HH(1);
k42 = HH(2);
% 08 - Trinomial model: Weight = k50 + k51*Height^3 + k52*Height^2 + k53*Height
II = polyfit(Height_Data,Weight_Data,3); % Weight = k50 + k51*Height^3 + k52*Height^2 + k53*Height
k50 = II(4);
k51 = II(1);
k52 = II(2);
k53 = II(3);
