k10 = GG(2);
k1 = GG(1);
% 07 - Binomial model: Weight = k40 + k41*Height^2 + k42*Height
HH = polyfit(Height_Data,Weight_Data,2); % Weight = k40 + k41*Height^2 + k42*Height
k40 = HH(3);
k41 = HH(1);
k42 = HH(2);
% 08 - Trinomial model: Weight = k50 + k51*Height^3 + k52*Height^2 + k53*Height
